SELECT u.id, u.username, u.nickname, u.avatar_url, u.bio, u.gender, u.location, u.status, u.create_time FROM users u JOIN follows f ON u.id = f.followee_id WHERE f.follower_id = #{userId} AND f.deleted = 0 AND u.deleted = 0 AND u.status = 1
AND (u.nickname ILIKE CONCAT('%', #{keyword}, '%') OR u.username ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY f.create_time DESC LIMIT #{limit}
